flake.nix<pre><code>{
  description = "greetsrc — Logos module wrapping an in-repo C library source";

  inputs = {
    logos-module-builder.url = "github:logos-co/logos-module-builder";
  };

  outputs = inputs@{ logos-module-builder, ... }:
    logos-module-builder.lib.mkLogosModule {
      src = ./.;
      configFile = ./metadata.json;
      flakeInputs = inputs;
      # No externalLibInputs: the library source (lib/greet.c) lives in this repo
      # and is compiled into the plugin by CMakeLists.txt.
    };
}
</code></pre>
